// Duplicate/alias mon_1 to begonia_1 as fallback sprout
static const uint8_t* kBaked_mon_1 = kBaked_begonia_1;

static const uint8_t* getBakedPlantSprite(uint8_t petType, uint8_t stage) {
  // petType: 0=Monstera, 1=Begonia, 2=Alocasia
  // stage: 1=Hatchling/Sprout, 2=Youngster/Sapling, 3=Companion/Mature, 4=Elder/Prized
  if (petType == 0) {
    if (stage == 1) return kBaked_mon_1;
    if (stage == 2) return kBaked_mon_2;
    if (stage == 3) return kBaked_mon_3;
    if (stage == 4) return kBaked_mon_4;
  } else if (petType == 1) {
    if (stage == 1) return kBaked_begonia_1;
    if (stage == 2) return kBaked_begonia_2;
    if (stage == 3) return kBaked_begonia_3;
    if (stage == 4) return kBaked_begonia_4;
  } else if (petType == 2) {
    if (stage == 1) return kBaked_alo_1;
    if (stage == 2) return kBaked_alo_2;
    if (stage == 3) return kBaked_alo_3;
    if (stage == 4) return kBaked_alo_4;
  }
  return nullptr;
}
